import React from "react";
import { Routes, Route } from "react-router-dom";

import RequireAuth from "../components/RequireAuth";

import Home from "../pages/Home";
import Login from "../pages/Auth/Login";
import Register from "../pages/Auth/Register";

import VehicleList from "../pages/Vehicles/VehicleList";
import AddVehicle from "../pages/Vehicles/AddVehicle";
import EditVehicle from "../pages/Vehicles/EditVehicle";

import AppointmentList from "../pages/Appointments/AppointmentList";
import AddAppointment from "../pages/Appointments/AddAppointment";
import EditAppointment from "../pages/Appointments/EditAppointment";

import CustomerBookAppointment from "../pages/Appointments/CustomerBookAppointment";
import MyAppointments from "../pages/Appointments/MyAppointments";
import EditMyAppointment from "../pages/Appointments/EditMyAppointment";

import CreateStaff from "../pages/Admin/CreateStaff";
import DocumentList from "../pages/Documents/DocumentList";
import AddDocument from "../pages/Documents/AddDocument";
import EditDocument from "../pages/Documents/EditDocument";

import SaleList from "../pages/Sales/SaleList";
import AddSale from "../pages/Sales/AddSale";

export default function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<Home />} />

      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      <Route path="/vehicles" element={<VehicleList />} />

      {/* Manager/Admin only */}
      <Route
        path="/vehicles/add"
        element={
          <RequireAuth roles={["manager", "admin"]}>
            <AddVehicle />
          </RequireAuth>
        }
      />
      <Route path="/vehicles/edit/:id" element={<EditVehicle />} />

      {/* Staff/Manager/Admin appointments */}
      <Route
        path="/appointments"
        element={
          <RequireAuth roles={["staff", "manager", "admin"]}>
            <AppointmentList />
          </RequireAuth>
        }
      />
      <Route
        path="/appointments/add"
        element={
          <RequireAuth roles={["staff", "manager", "admin"]}>
            <AddAppointment />
          </RequireAuth>
        }
      />
      <Route
        path="/appointments/edit/:id"
        element={
          <RequireAuth roles={["staff", "manager", "admin"]}>
            <EditAppointment />
          </RequireAuth>
        }
      />

      {/* Client booking */}
      <Route
        path="/book-appointment"
        element={
          <RequireAuth roles={["client"]}>
            <CustomerBookAppointment />
          </RequireAuth>
        }
      />
      <Route
        path="/my-appointments"
        element={
          <RequireAuth roles={["client"]}>
            <MyAppointments />
          </RequireAuth>
        }
      />
      <Route
        path="/edit-my-appointment/:id"
        element={
          <RequireAuth roles={["client"]}>
            <EditMyAppointment />
          </RequireAuth>
        }
      />

      {/* Admin create staff */}
        <Route path="/admin/create-staff" element={<CreateStaff />} />
        <Route path="/documents" element={<DocumentList />} />
        <Route path="/documents/add" element={<AddDocument />} />
        <Route path="/documents/edit/:id" element={<EditDocument />} />
    </Routes>

  );
}
